-- =====================================================================-- 0013_views.sql-- Views definer-ish (default) com WHERE manual de tenant + escopo.-- Owner = postgres -> RLS da base não é aplicada via view; segurança-- vem da WHERE explícita + REVOKE em 0014.-- =====================================================================-- ---------- assignments_admin ------------ Todas as colunas, restrita a owner/admin do tenant atual.create or replace view public.assignments_admin asselect a.*from public.assignments awhere a.tenant_id = app.current_tenant_id()  and app.is_admin_or_owner();-- ---------- assignments_safe ------------ Subset seguro (sem magic_token_hash, sem evaluator_*),-- escopo: manager (escopo gerencial) ou participant (avaliado próprio).create or replace view public.assignments_safe asselect  a.id,  a.tenant_id,  a.cycle_id,  a.evaluated_cycle_participant_id,  a.relationship_code,  a.questionnaire_id,  a.status,  a.invited_at,  a.completed_at,  a.created_atfrom public.assignments awhere a.tenant_id = app.current_tenant_id()  and app.is_active_member()  and (    app.manages_person(      (select cp.person_id       from public.cycle_participants cp       where cp.id = a.evaluated_cycle_participant_id)    )    or    (select cp.person_id     from public.cycle_participants cp     where cp.id = a.evaluated_cycle_participant_id)    = app.person_id_for_user()  );-- ---------- comments_published ------------ Comments só aparecem quando o grupo respectivo atinge n_minimum.-- Nunca expõe assignment_id (preserva anonimato).create or replace view public.comments_published asselect  c.id,  c.tenant_id,  cy.id                              as cycle_id,  a.evaluated_cycle_participant_id,  ss.relationship_group,  c.body,  c.created_atfrom public.comments cjoin public.assignments a on a.id = c.assignment_idjoin public.cycles cy     on cy.id = a.cycle_idjoin public.score_snapshots ss  on ss.cycle_id              = a.cycle_id and ss.cycle_participant_id  = a.evaluated_cycle_participant_id and ss.relationship_code     = a.relationship_codewhere cy.tenant_id = app.current_tenant_id()  and ss.visibility_status = 'visible'  and ss.response_count >= coalesce(        (select t.n_minimum_default         from public.templates t         where t.id = cy.template_id),        3      )  and (    app.is_admin_or_owner()    or app.manages_person(        (select cp.person_id         from public.cycle_participants cp         where cp.id = a.evaluated_cycle_participant_id)      )    or (      (select cp.person_id       from public.cycle_participants cp       where cp.id = a.evaluated_cycle_participant_id)      = app.person_id_for_user()      and app.report_released(cy.id)    )  );